303→	if input.Tags != nil {
304→		sets = append(sets, fmt.Sprintf("tags = $%d", paramIdx))
305→		args = append(args, input.Tags)
306→		paramIdx++
307→	}
308→	if input.Sensitivity != nil {
309→		sets = append(sets, fmt.Sprintf("sensitivity = $%d", paramIdx))
310→		args = append(args, *input.Sensitivity)
311→		paramIdx++ //nolint:ineffassign // keeps pattern consistent for future fields
312→	}
313→
314→	if len(sets) == 0 {
315→		return s.GetByID(ctx, ownerID, itemID)
316→	}
317→
318→	query := fmt.Sprintf(`UPDATE items SET %s WHERE owner_id = $1 AND id = $2 RETURNING %s`,
319→		joinSets(sets), itemColumns)
320→
321→	row := s.pool.QueryRow(ctx, query, args...)
322→	it, err := scanItem(row)
323→	if errors.Is(err, pgx.ErrNoRows) {
324→		return nil, fmt.Errorf("item: update: not found")
325→	}
326→	if err != nil {
327→		return nil, fmt.Errorf("item: update: %w", err)
328→	}
329→	return it, nil
330→}
